function tocHighlighter(){return{headings:[],links:[],debouncedScroll:null,init(){const e=document.querySelector("#TableOfContents");if(!e||window.getComputedStyle(e.parentElement).display==="none")return;this.links=[...e.querySelectorAll("a")],this.headings=this.links.map(e=>document.getElementById(e.getAttribute("href")?.replace("#",""))).filter(Boolean),this.debouncedScroll=this.debounce(this.onScroll.bind(this),300),this.debouncedScroll()},onScroll(){let e=null,t=1/0;this.headings.forEach((n,s)=>{const o=n.getBoundingClientRect(),i=Math.abs(o.top);o.top<window.innerHeight&&i<t&&(t=i,e=s)}),e!==null&&this.links[e]&&this.setActive(this.links[e])},setActive(e){this.links.forEach(e=>e.classList.remove("menu-active")),e.classList.add("menu-active")},debounce(e,t){let n;return function(...s){clearTimeout(n),n=setTimeout(()=>e.apply(this,s),t)}}}}